sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {

    const shortDescFieldName = 'short_description';
    const numberFieldName = 'number';
    const incidentIds = [];
    const shortDescValue = current.getValue(shortDescFieldName);
    const instanceUrl = gs.getProperty('glide.servlet.uri');
    const shortDescFieldTranslatedName = current.getElement(shortDescFieldName).getLabel();
    const worknoteMessage = gs.getMessage('custom_duplicate_incident_has_been_close').replace('{1}', shortDescFieldTranslatedName);

    let duplicateIncidentGR = new GlideRecord('incident');
    duplicateIncidentGR.addActiveQuery();
    duplicateIncidentGR.addQuery(shortDescFieldName, 'CONTAINS', shortDescValue);
    duplicateIncidentGR.addQuery('sys_id', '!=', current.getUniqueValue());
    duplicateIncidentGR.query();

    let tempWorkNote = null;
    let tempWorkNoteMessage = null;

    while (duplicateIncidentGR.next()) {
        tempWorkNote = duplicateIncidentGR.work_notes.getJournalEntry(-1);

        if (tempWorkNote?.indexOf(current.getValue(numberFieldName)) !== -1)
            continue;

        tempWorkNoteMessage = worknoteMessage.replace(
            '{0}',
            createClickableLink(
                instanceUrl + current.getLink(),
                current.getValue(numberFieldName)
            )
        );

        duplicateIncidentGR.work_notes = tempWorkNoteMessage;
        duplicateIncidentGR.update();
    }

    /**
     * 
     */
    function createClickableLink(url, displayText) {
        return "[code]<a href='" + url + "' target='_blank'>" + displayText + "</a>[/code]";
    }

})(current, previous);
